// Parsear CSV bancario del body (base64)
const body = $('Webhook').first().json.body;
const csvBase64 = body.csv_base64;
const empresaId = body.empresa_id || 0;
const csvText = Buffer.from(csvBase64, 'base64').toString('utf-8');
const lines = csvText.split('\n').filter(l => l.trim());

// Detectar separador
const sep = lines[0].includes(';') ? ';' : lines[0].includes('\t') ? '\t' : ',';
const headers = lines[0].split(sep).map(h => h.trim().toLowerCase());

const movimientos = [];
for (let i = 1; i < lines.length; i++) {
  const cols = lines[i].split(sep);
  if (cols.length < 3) continue;

  // Intentar detectar columnas: fecha, concepto, importe, saldo
  const mov = {
    fecha: cols[0]?.trim() || '',
    concepto: cols[1]?.trim() || '',
    importe: parseFloat((cols[2] || '0').replace(',', '.').replace(/[^0-9.-]/g, '')) || 0,
    saldo: cols[3] ? parseFloat((cols[3] || '0').replace(',', '.').replace(/[^0-9.-]/g, '')) : null,
    empresa_id: empresaId,
    conciliado: false,
    factura_id: null
  };
  movimientos.push(mov);
}

return [{ json: { movimientos, total: movimientos.length } }];

// Matching automático: comparar importes de movimientos con totales de facturas
const movData = $('Parsear CSV').first().json;
const facturas = $('Leer Facturas PostgreSQL').all().map(i => i.json);
const movimientos = movData.movimientos || [];

let conciliados = 0;
const resultados = [];

for (const mov of movimientos) {
  let matched = null;
  const absImporte = Math.abs(mov.importe);

  // Buscar factura con mismo importe (tolerancia 0.05€)
  for (const f of facturas) {
    const totalFact = Math.abs(Number(f.total_factura) || 0);
    if (Math.abs(totalFact - absImporte) < 0.05) {
      // Comprobar que no esté ya conciliada
      if (!resultados.some(r => r.factura_id === f.Id)) {
        matched = f;
        break;
      }
    }
  }

  if (matched) {
    conciliados++;
    resultados.push({
      ...mov,
      conciliado: true,
      factura_id: matched.Id,
      factura_numero: matched.numero_factura,
      factura_emisor: matched.nombre_emisor
    });
  } else {
    resultados.push({ ...mov, conciliado: false, factura_id: null });
  }
}

return [{
  json: {
    success: true,
    total_movimientos: movimientos.length,
    conciliados: conciliados,
    sin_conciliar: movimientos.length - conciliados,
    porcentaje: movimientos.length > 0 ? Math.round(conciliados / movimientos.length * 100) : 0,
    movimientos: resultados
  }
}];
